### `swift`

```swift
import Foundation

struct Paste: Sendable, Hashable {
  var slug: String
  var title: String

  func excerpt(from body: String, max: Int = 120) -> String {
    let s = body.replacingOccurrences(of: "\n", with: " ")
      .trimmingCharacters(in: .whitespacesAndNewlines)
    if s.count <= max { return s }
    let idx = s.index(s.startIndex, offsetBy: max - 1)
    return String(s[..<idx]) + "…"
  }
}

```

### `kotlin`

```kotlin
package com.woxbin.demo

data class Paste(
    val slug: String,
    val title: String,
    val pinned: Boolean = false,
) {
    fun excerpt(body: String, max: Int = 120): String {
        val s = body.replace("\n", " ").trim()
        return if (s.length <= max) s else s.take(max - 1) + "…"
    }
}

fun main() {
    println(Paste("x", "Demo"))
}
```


